def is_note_in_range(notes, lower_bound, upper_bound):
    def parse_note(note):
        # Extract the note and octave
        note_part = note.split(" ")[0]
        octave = note.split(" ")[1]
        return note_part, int(octave)

    # Check if all notes are within the range
    for note in notes:
        note_part, octave = parse_note(note)
        if not (lower_bound <= note_part <= upper_bound):
            return False
        if not (int(lower_bound.split(" ")[1]) <= octave <= int(upper_bound.split(" ")[1])):
            return False
